import React from 'react';
import type { WidgetRendererProps } from '../../shared/overlayRenderer/widgetContract';
import type { ChatOverlayState } from '../types/unifiedOverlayState';

export function ChatOverlayWidget(props: WidgetRendererProps<ChatOverlayState>): React.ReactElement | null {
  const { state } = props;
  
  if (!state.messages || state.messages.length === 0) {
    return null;
  }

  return (
    <div style={{
      display: 'flex',
      flexDirection: 'column-reverse',
      gap: '8px',
      padding: '8px',
      width: '100%',
      height: '100%',
      overflow: 'visible',
      pointerEvents: 'none',
      fontFamily: 'Inter, system-ui, sans-serif',
      fontSize: '16px',
      lineHeight: 1.4,
    }}>
      {state.messages.map((msg) => (
        <div key={msg.id} style={{
          display: 'flex',
          alignItems: 'flex-start',
          gap: '8px',
          maxWidth: '100%',
          wordBreak: 'break-word',
          background: 'rgba(0, 0, 0, 0.4)',
          borderRadius: '8px',
          padding: '8px 12px',
        }}>
          <span style={{
            fontWeight: 600,
            color: msg.color || '#a5b4fc',
            flexShrink: 0,
          }}>
            {msg.username}
          </span>
          <span style={{ color: '#ffffff' }}>: </span>
          <span style={{ color: '#ffffff', flex: 1 }}>
            {msg.tokens.map((token, idx) => {
              if (token.type === 'text') {
                return <span key={idx}>{token.text}</span>;
              }
              // emote token
              return (
                <img
                  key={idx}
                  src={token.url}
                  alt={token.name}
                  style={{
                    height: '1.5em',
                    verticalAlign: 'middle',
                    display: 'inline-block',
                  }}
                />
              );
            })}
          </span>
        </div>
      ))}
    </div>
  );
}
