/**
 * widgetRenderers.ts
 *
 * Registry of React renderers for widgets on the unified state path.
 * Only register widgets whose renderers consume UnifiedOverlayState.
 * Unregistered widgets fall back to the IIFE script path in registerWidgets().
 */

import { registerWidgetRenderer } from '../shared/overlayRenderer/widgetContract';
import { ChatOverlayWidget }    from './renderers/ChatOverlayWidget';
import { AlertBoxWidget }       from './renderers/AlertBoxWidget';
import { SubCounterWidget }     from './renderers/SubCounterWidget';
import { TtsPlayerWidget }      from './renderers/TtsPlayerWidget';
import { EventConsoleWidget }   from './renderers/EventConsoleWidget';

registerWidgetRenderer('chat-overlay',          ChatOverlayWidget);
registerWidgetRenderer('alert-box-widget',      AlertBoxWidget);
registerWidgetRenderer('sub-counter',           SubCounterWidget);
registerWidgetRenderer('tts-player',            TtsPlayerWidget);
registerWidgetRenderer('event-console-widget',  EventConsoleWidget);
